"cssTech":"border: 1px solid rgba(0,255,255,0.5), color: #00FFFF, background: transparent or rgba(0,0,0,0.8), font-family: monospace, text-shadow: 0 0 5px cyan","checklist":"☐ Fine lines 1px, ☐ Neon glow text/borders, ☐ Monospaced font, ☐ Dark/Transparent BG, ☐ Decorative tech markers, ☐ Holographic feel","designVars":"--hud-color: #00FFFF, --bg-color: rgba(0,10,20,0.9), --line-width: 1px, --glow: 0 0 5px, --font: monospace","deepSpec":"","deepFullName":"","deepDesc":"","deepBestFor":""},{"name":"Pixel Art","type":"General","keywords":"Retro, 8-bit, 16-bit, gaming, blocky, nostalgic, pixelated, arcade","primaryColors":"Primary colors (NES Palette), brights, limited palette","secondaryColors":"Black outlines, shading via dithering or block colors","effects":"Frame-by-frame sprite animation, blinking cursor, instant transitions, marquee text","bestFor":"Indie games, retro tools, creative portfolios, nostalgia marketing, Web3/NFT","dontUseFor":"Professional corporate, modern SaaS, high-res photography sites","darkMode":"✓ Full","performance":"⚡ Excellent","accessibility":"✓ Good (if contrast ok)","complexity":"Medium","aiPrompt":"Design a pixel art inspired interface. Use: pixelated fonts, 8-bit or 16-bit aesthetic, sharp edges (image-rendering: pixelated), limited color palette, blocky UI elements, retro gaming feel.","cssTech":"font-family: \'Press Start 2P\', image-rendering: pixelated, box-shadow: 4px 0 0 #000 (pixel border), no anti-aliasing","checklist":"☐ Pixelated fonts loaded, ☐ Images sharp (no blur), ☐ CSS box-shadow for pixel borders, ☐ Retro palette, ☐ Blocky layout","designVars":"--pixel-size: 4px, --font: pixel font, --border-style: pixel-shadow, --anti-alias: none","deepSpec":"","deepFullName":"","deepDesc":"","deepBestFor":""},{"name":"Bento Grids","type":"General","keywords":"Apple-style, modular, cards, organized, clean, hierarchy, grid, rounded, soft","primaryColors":"Off-white #F5F5F7, Clean White #FFFFFF, Text #1D1D1F","secondaryColors":"Subtle accents, soft shadows, blurred backdrops","effects":"Hover scale (1.02), soft shadow expansion, smooth layout shifts, content reveal","bestFor":"Product features, dashboards, personal sites, marketing summaries, galleries","dontUseFor":"Long-form reading, data tables, complex forms","darkMode":"✓ Full","performance":"⚡ Excellent","accessibility":"✓ WCAG AA","complexity":"Low","aiPrompt":"Design a Bento Grid layout. Use: modular grid system, rounded corners (16-24px), different card sizes (1x1, 2x1, 2x2), card-based hierarchy, soft backgrounds (#F5F5F7), subtle borders, content-first, Apple-style aesthetic.","cssTech":"display: grid, grid-template-columns: repeat(auto-fit, minmax(...)), gap: 1rem, border-radius: 20px, background: #FFF, box-shadow: subtle","checklist":"☐ Grid layout (CSS Grid), ☐ Rounded corners 16-24px, ☐ Varied card spans, ☐ Content fits card size, ☐ Responsive re-flow, ☐ Apple-like aesthetic","designVars":"--grid-gap: 20px, --card-radius: 24px, --card-bg: #FFFFFF, --page-bg: #F5F5F7, --shadow: soft","deepSpec":"","deepFullName":"","deepDesc":"","deepBestFor":""},{"name":"Spatial UI (VisionOS)","type":"General","keywords":"Glass, depth, immersion, spatial, translucent, gaze, gesture, apple, vision-pro","primaryColors":"Frosted Glass #FFFFFF (15-30% opacity), System White","secondaryColors":"Vibrant system colors for active states, deep shadows for depth","effects":"Parallax depth, dynamic lighting response, gaze-hover effects, smooth scale on focus","bestFor":"Spatial computing apps, VR/AR interfaces, immersive media, futuristic dashboards","dontUseFor":"Text-heavy documents, high-contrast requirements, non-3D capable devices","darkMode":"✓ Full","performance":"⚠ Moderate (blur cost)","accessibility":"⚠ Contrast risks","complexity":"High","aiPrompt":"Design a VisionOS-style spatial interface. Use: frosted glass panels, depth layers, translucent backgrounds (15-30% opacity), vibrant colors for active states, gaze-hover effects, floating windows, immersive feel.","cssTech":"backdrop-filter: blur(40px) saturate(180%), background: rgba(255,255,255,0.2), border-radius: 24px, box-shadow: 0 8px 32px rgba(0,0,0,0.1), transform: scale on focus, depth via shadows","checklist":"☐ Glass effect visible, ☐ Depth layers clear, ☐ Hover states defined, ☐ Colors vibrant on active, ☐ Floating feel achieved, ☐ Contrast maintained","designVars":"--glass-bg: rgba(255,255,255,0.2), --glass-blur: 40px, --glass-saturate: 180%, --window-radius: 24px, --depth-shadow: 0 8px 32px rgba(0,0,0,0.1), --focus-scale: 1.02","deepSpec":"","deepFullName":"","deepDesc":"","deepBestFor":""},{"name":"E-Ink / Paper","type":"General","keywords":"Paper-like, matte, high contrast, texture, reading, calm, slow tech, monochrome","primaryColors":"Off-White #FDFBF7, Paper White #F5F5F5, Ink Black #1A1A1A","secondaryColors":"Pencil Grey #4A4A4A, Highlighter Yellow #FFFF00 (accent)","effects":"No motion blur, distinct page turns, grain/noise texture, sharp transitions (no fade)","bestFor":"Reading apps, digital newspapers, minimal journals, distraction-free writing, slow-living brands","dontUseFor":"Gaming, video platforms, high-energy marketing, dark mode dependent apps","darkMode":"✗ Low (inverted only)","performance":"⚡ Excellent","accessibility":"✓ WCAG AAA","complexity":"Low","aiPrompt":"Design an e-ink/paper style interface. Use: high contrast black on off-white, paper texture, no animations (instant transitions), reading-focused, minimal UI chrome, distraction-free, calm aesthetic, monochrome.","cssTech":"background: #FDFBF7 (paper white), color: #1A1A1A, transition: none, font-family: serif for reading, no gradients, border: 1px solid #E0E0E0, texture overlay (noise)","checklist":"☐ Paper background color, ☐ High contrast text, ☐ No animations, ☐ Reading optimized, ☐ Distraction-free, ☐ Print-friendly","designVars":"--paper-bg: #FDFBF7, --ink-color: #1A1A1A, --pencil-grey: #4A4A4A, --border-color: #E0E0E0, --font-reading: Georgia, --transition: none","de